// Filter events happening in 24h, 6h, or 10min
const now = new Date();
const events = $input.all()[0].json.events || [];

const filtered = events.map(event => {
  const eventTime = new Date(event.eventDate);
  const diffMs = eventTime - now;
  const diffHours = diffMs / (1000 * 60 * 60);
  const diffMinutes = diffMs / (1000 * 60);

  let countdownType = null;
  if (diffHours >= 23.5 && diffHours <= 24.5) countdownType = 'T-24h';
  else if (diffHours >= 5.5 && diffHours <= 6.5) countdownType = 'T-6h';
  else if (diffMinutes >= 9 && diffMinutes <= 11) countdownType = 'T-10min';

  if (countdownType) {
    return { ...event, countdownType, timeRemaining: diffHours > 1 ? `${Math.round(diffHours)}h` : `${Math.round(diffMinutes)}min` };
  }
  return null;
}).filter(e => e !== null);

return filtered.map(e => ({ json: e }));

